const results = $input.item.json.results || [];
const meuUserId = 356970934;
const output = [];

for (const item of results) {
  // IGNORAR transferências internas CDI/Potes
  if (item.operation_type === 'partition_transfer') {
    continue;
  }

  // Identificar entrada ou saída
  const collectorId = item.collector_id || item.collector?.id;
  const payerId = item.payer_id;
  let tipo = '';
  let destinatario = '';

  if (collectorId === meuUserId && payerId !== meuUserId) {
    // ENTRADA: Você recebeu
    tipo = 'entrada';
    destinatario = item.payer?.identification?.long_name || 
                   item.point_of_interaction?.transaction_data?.commerce?.name ||
                   'Não identificado';
  } else if (payerId === meuUserId && collectorId !== meuUserId) {
    // SAÍDA: Você pagou
    tipo = 'saida';
    destinatario = item.point_of_interaction?.transaction_data?.commerce?.name || 'Não identificado';
  } else {
    // Ignorar resto (transações internas)
    continue;
  }

  // Limpar destinatário
  destinatario = destinatario
    .trim()
    .replace(/^MP\*/i, '')
    .replace(/\s+/g, ' ');

  // Forma de pagamento
  let formaPagamento = '';
  const subUnit = item.point_of_interaction?.business_info?.sub_unit;
  const paymentMethodId = item.payment_method_id;

  if (paymentMethodId === 'pix') {
    formaPagamento = 'PIX';
  } else if (subUnit === 'debit_card') {
    formaPagamento = 'Débito';
  } else if (subUnit === 'credit_card') {
    formaPagamento = 'Crédito';
  } else if (paymentMethodId === 'account_money') {
    formaPagamento = 'Saldo MP';
  } else {
    formaPagamento = paymentMethodId || 'Outro';
  }

  // Timezone São Paulo
  const date = new Date(item.date_created);
  const dataSP = new Date(date.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
  const day = String(dataSP.getDate()).padStart(2, '0');
  const month = String(dataSP.getMonth() + 1).padStart(2, '0');
  const year = dataSP.getFullYear();
  const hours = String(dataSP.getHours()).padStart(2, '0');
  const minutes = String(dataSP.getMinutes()).padStart(2, '0');
  const dataFormatada = `${day}/${month}/${year} ${hours}:${minutes}`;

  output.push({
    json: {
      payment_id: item.id,
      tipo: tipo,
      status: item.status,
      transaction_amount: item.transaction_amount,
      payment_method_id: formaPagamento,
      destinatario: destinatario,
      date_created: dataFormatada
    }
  });
}

return output;

